Something like:
```
def fastq_reader(filename):
  with open(filename, 'r') as infile:
     name = infile.readline().rstrip()
     while True:
       seq = ""
       for s in infile:
         if s[0] == '+':
           commentp = s.rstrip()
           break
         else:
           seq += s.rstrip()
       qual = ""
       for q in infile:
         if q[0] == '@':
           yield name, seq, qual
           name = q.rstrip()
           break
         else:
           qual += q.rstrip()
       else:
         yield name, seq, qual
         return
```

