A more useful implementation:

```python

import collections
import wrapt

class ProxyDict(collections.MutableMapping):
    '''
    Dictionary that updates `ObjectProxy` wrapped values when setting items
    '''
    def __init__(self):
        self._data = {}

    def __getitem__(self, key):
        return self._data[key]

    def __setitem__(self, key, value):
        if key in self._data and isinstance(self._data[key], wrapt.ObjectProxy):
            self._data[key].__wrapped__ = value
        else:
            self._data[key] = value

    def __delitem__(self, key):
        del self._data[key]

    def __iter__(self):
        return iter(self._data)

    def __len__(self):
        return len(self._data)

d = ProxyDict()
val = d['a'] = wrapt.ObjectProxy('foo')
print(val) # foo
d['a'] = 'bar'
print(val) # bar
```

